       }\n            .article-data-callout .callout-flow-arrow {\n                transform: rotate(90deg);\n            }\n            .related-grid {\n                grid-template-columns: 1fr;\n                gap: 16px;\n            }\n            .related-header {\n                font-size: 26px;\n            }\n            .article-cta {\n                padding: 80px 20px;\n            }\n            .article-cta h2 {\n                font-size: 26px;\n            }\n        }\n        /* ===== Reduced Motion ===== */\n        @media (prefers-reduced-motion: reduce) {\n            .fade-in-section {\n                opacity: 1;\n                transform: none;\n                transition: none;\n            }\n            .article-back-link,\n            .related-card,\n            .related-card-link,\n            .article-cta-btn,\n            .article-cta-btn svg {\n                transition: none;\n            }\n            .related-card:hover,\n            .article-cta-btn:hover {\n                transform: none;\n            }\n            .article-cta-btn:hover svg {\n                transform: none;\n            }\n            .dw-d-bg,\n            .dw-wave-circles,\n            .dw-wave-fade {\n                animation: none;\n            }\n        }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}</style><!-- /wp:html -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Hero"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Hero: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Hero: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="article-hero" style="position: relative; overflow: hidden;">\n        <div class="dw-d-bg dw-d-bg--corner-tl" style="opacity: 0.06;"></div>\n        <div class="article-hero-inner" style="position: relative; z-index: 2;">\n            <a href="/blog/" class="article-back-link">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>\n                Back to Insights\n            </a>\n            <div class="article-category-badge">Cost Management</div>\n            <h1>Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve</h1>\n            <div class="article-meta">\n                <span>7 min read</span>\n                <div class="article-meta-divider"></div>\n                <span>February 2026</span>\n            </div>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Body"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Body: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Body: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><!-- Article Hero -->\n    <section class="article-hero" style="position: relative; overflow: hidden;">\n        <div class="dw-d-bg dw-d-bg--corner-tl" style="opacity: 0.06;"></div>\n        <div class="article-hero-inner" style="position: relative; z-index: 2;">\n            <a href="/blog/" class="article-back-link">\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="19" y1="12" x2="5" y2="12"/><polyline points="12 19 5 12 12 5"/></svg>\n                Back to Insights\n            </a>\n            <div class="article-category-badge">Cost Management</div>\n            <h1>Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve</h1>\n            <div class="article-meta">\n                <span>7 min read</span>\n                <div class="article-meta-divider"></div>\n                <span>February 2026</span>\n            </div>\n        </div>\n    </section>\n\n    <!-- Article Body -->\n    <section class="article-body">\n        <div class="article-body-inner">\n\n            <!-- Opening -->\n            <div class="fade-in-section">\n                <p>In Thai manufacturing, one production run often produces multiple outputs. A plastics injection cycle might yield three different parts from one mold. A food processing batch might produce a primary product, a by-product, and a co-product. A chemical reaction might generate two saleable outputs and a recyclable residue.</p>\n                <p>This is not an edge case. It is daily reality on thousands of shop floors across Thailand.</p>\n                <p>The question is simple: if your ERP cannot accurately allocate costs across multiple outputs from a single production run, your cost data is fiction. And if your cost data is fiction, so are your margins, your quotes, and your pricing strategy.</p>\n            </div>\n\n            <!-- Section: The Multi-Output Reality -->\n            <div class="fade-in-section">\n                <h2>The Multi-Output Reality</h2>\n                <p>Many Thai industries produce co-products and by-products as a natural part of manufacturing. This is not a special scenario that needs a workaround. It is the fundamental way these factories operate.</p>\n                <ul>\n                    <li><strong>Plastics injection molding:</strong> Multi-cavity molds produce different parts in a single cycle. Runners and sprues are recycled back into raw material. One machine setup yields multiple SKUs simultaneously.</li>\n                    <li><strong>Food and beverage processing:</strong> A single batch of raw material produces a primary product alongside by-products that carry commercial value -- cooking oils, animal feed, flavoring extracts.</li>\n                    <li><strong>Chemical manufacturing:</strong> Chemical reactions inherently produce multiple outputs. A single process might yield a primary compound, a secondary compound, and a recoverable solvent.</li>\n                    <li><strong>Metal processing:</strong> Stamping, cutting, and machining operations produce primary parts alongside scrap metal with resale value. Die-casting generates both finished components and reusable overflow material.</li>\n                </ul>\n            </div>\n\n            <div class="article-pull-quote fade-in-section">\n                <p>When one work order produces three outputs, your ERP needs to know how to split the cost accurately -- not just divide by three.</p>\n            </div>\n\n            <!-- Section: How Most ERPs Get This Wrong -->\n            <div class="fade-in-section">\n                <h2>How Most ERPs Get This Wrong</h2>\n                <p>The standard ERP architecture assumes a clean, simple relationship: one work order produces one output item. One BOM (Bill of Materials) in, one finished good out. This works perfectly for single-product assembly lines. It falls apart completely in co-product manufacturing.</p>\n                <p>When factories running these systems encounter multi-output production, they are forced into workarounds:</p>\n                <ul>\n                    <li><strong>Separate work orders for each output.</strong> The factory creates three work orders to represent what is actually one production run. This destroys the cost linkage between outputs. Material consumption cannot be accurately split because each work order pretends it is an independent process.</li>\n                    <li><strong>Manual journal entries to redistribute costs.</strong> The accounting team manually moves costs between accounts at month-end to approximate the correct allocation. This is error-prone, audit-risky, and always delayed. By the time the numbers are corrected, decisions have already been made on wrong data.</li>\n                    <li><strong>Ignore co-product costing entirely.</strong> Some factories simply assign zero cost to by-products and load everything onto the primary product. The P&L for the primary product looks worse than reality, the by-product appears to have infinite margins, and management decisions are based on distorted numbers.</li>\n                </ul>\n                <p>The most common mid-market ERP systems encountered in Thai manufacturing all require one or more of these workarounds to handle co-product scenarios. None of them support native multi-output work orders at the SME tier.</p>\n            </div>\n\n            <div class="article-data-callout fade-in-section">\n                <div class="article-data-callout-content">\n                    <div class="callout-flow">\n                        <span class="callout-flow-item">1 Production Run</span>\n                        <span class="callout-flow-arrow">&rarr;</span>\n                        <span class="callout-flow-item">3 Outputs</span>\n                        <span class="callout-flow-arrow">&rarr;</span>\n                        <span class="callout-flow-item">3 Separate Work Orders</span>\n                    </div>\n                    <div class="callout-result">0% Cost Accuracy</div>\n                    <div class="callout-label">The broken model that most ERPs force on multi-output factories</div>\n                </div>\n            </div>\n\n            <!-- Section: Native Co-Product Handling -->\n            <div class="fade-in-section">\n                <h2>Native Co-Product Handling</h2>\n                <p><a href="/products/erp/">DigiWin\'s manufacturing ERP</a> approaches co-product manufacturing the way the shop floor actually works: one work order can declare multiple output items. There is no workaround. There is no manual redistribution. The system is architected from the ground up to handle multi-output production as a first-class scenario.</p>\n                <p>Here is how it works in practice:</p>\n                <ul>\n                    <li><strong>One work order, multiple outputs.</strong> A single work order defines the production run, the input materials, and all expected output items -- primary products, co-products, and by-products. The system knows from the start that this run will produce multiple items.</li>\n                    <li><strong>Flexible cost allocation methods.</strong> Costs can be distributed across outputs by weight, by quantity, by market value, or by a custom formula that reflects your specific production reality. A plastics factory might allocate by weight. A food processor might allocate by market value. A chemical plant might use a custom formula based on purity grades.</li>\n                    <li><strong>Material consumption tracks to the work order.</strong> All raw materials, labor, and overhead are consumed against the work order, then distributed across all outputs according to the allocation method. There is no ambiguity about where costs went.</li>\n                    <li><strong>Accurate per-product costing.</strong> The result is a true cost for each output item that reflects manufacturing reality -- not an estimate, not a manual adjustment, not a guess.</li>\n                </ul>\n            </div>\n\n            <div class="article-highlight-box fade-in-section">\n                <p><strong>Co-product cost accounting is not an edge case.</strong> In plastics injection molding alone -- one of Thailand\'s largest manufacturing sectors -- multi-output production is the default reality. Any ERP that cannot handle this natively is not built for Thai manufacturing.</p>\n            </div>\n\n            <!-- Section: Why Accurate Costing Matters More Than You Think -->\n            <div class="fade-in-section">\n                <h2>Why Accurate Costing Matters More Than You Think</h2>\n                <p>Inaccurate cost allocation does not just produce wrong numbers on a report. It cascades into every decision the factory makes.</p>\n                <p><strong>Wrong cost equals wrong pricing equals wrong margins.</strong> If your system overstates the cost of your primary product and understates the cost of a co-product, you are setting prices based on fiction. You might be underpricing a high-value co-product -- essentially giving away margin on every order -- while overpricing your primary product and losing deals.</p>\n                <p><strong>Quoting accuracy suffers.</strong> When a customer asks for a price on Product A, and Product A happens to be a co-product from a shared production run, you need to know what it actually costs to produce. If your ERP cannot provide that number, your sales team is quoting blind. Win rates drop. Margins erode. And you never know why because the root cause is buried in your cost accounting.</p>\n                <p><strong>BOI compliance becomes harder.</strong> For BOI-promoted factories, material consumption must reconcile with all outputs from a production run, not just the primary product. If your system only tracks the primary output against the work order, the reconciliation between imported raw materials and finished goods will have gaps. Those gaps trigger supplementary tax exposure -- the same problem we detailed in our <a href="/blog/boi-compliance-jin-hai/" style="color: #0369a1;text-decoration:underline;">BOI compliance article</a>.</p>\n                <p><strong>Inventory valuation is distorted.</strong> By-products sitting in your warehouse with zero cost assigned? Your balance sheet does not reflect reality. Auditors will notice. So will your bank when you apply for a credit facility and your inventory numbers do not add up.</p>\n            </div>\n\n            <div class="article-pull-quote fade-in-section">\n                <p>If you are pricing co-products based on estimated costs, you might be giving away your margins on every order.</p>\n            </div>\n\n            <!-- Section: The Competitive Landscape -->\n            <div class="fade-in-section">\n                <h2>The Competitive Landscape</h2>\n                <p>This is not a minor feature gap. It is a fundamental architectural limitation in competing systems.</p>\n                <p><strong>Most mid-market ERP systems</strong> common in Thai small and medium enterprises have no native co-product work order capability. The production module assumes one work order equals one output. To work around this, factories either create multiple work orders (destroying cost linkage) or use manual journal entries (introducing delay and error). Upgrading to enterprise-tier platforms to access co-product capabilities would cost 10 to 50 times more than the SME ERP itself -- putting it out of reach for the vast majority of Thai manufacturers.</p>\n                <p><strong>Chinese ERP vendors</strong> expanding rapidly in Thailand face the same architectural constraint at their SME product tiers. Their manufacturing modules were designed for single-output production. Co-product handling, where it exists at all, requires customization that increases implementation cost and ongoing maintenance burden.</p>\n                <p><strong>DigiWin includes native co-product support</strong> in both the T100 (mid-market ERP) and iGP/WorkFlow (SME ERP) platforms. This is not a premium add-on. It is not a customization. It is built into the standard manufacturing module because DigiWin was designed from day one for manufacturing -- including the multi-output processes that are standard in plastics, food, chemical, and metal processing industries.</p>\n                <p>For distributors and ERP consultants evaluating which product to bring to market: co-product handling is a proven deal-winning differentiator. In any competitive evaluation involving a plastics, food, or chemical manufacturer, the ability to demonstrate native co-product cost accounting ends the conversation in your favor.</p>\n            </div>\n\n        </div>\n    </section>\n\n    <!-- FAQ Section -->\n    <section class="dw-section" style="padding: 60px 0; background: #f8fafc;">\n      <div style="max-width: 800px; margin: 0 auto; padding: 0 24px;">\n        <h2 style="font-family: \'Noto Sans\', sans-serif; font-size: 28px; font-weight: 700; color: #000864; margin-bottom: 32px;">Frequently Asked Questions</h2>\n        <div style="display: flex; flex-direction: column; gap: 12px;">\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">What is co-product cost accounting?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Co-product cost accounting is the process of accurately allocating production costs when a single manufacturing run produces multiple outputs. For example, a plastics injection cycle might yield three different parts from one mold, or a chemical reaction might generate two saleable compounds and a recyclable residue. The system must distribute raw material costs, labor, and overhead across all outputs using methods such as allocation by weight, quantity, market value, or custom formulas — rather than loading all costs onto a single primary product.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">How do ERPs handle co-products?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Most ERP systems assume one work order produces one output, which falls apart in co-product manufacturing. They force factories into workarounds: creating separate work orders for each output (destroying cost linkage), making manual journal entries to redistribute costs at month-end (error-prone and delayed), or ignoring co-product costing entirely (assigning zero cost to by-products). DigiWin handles co-products natively — one work order can declare multiple output items with flexible cost allocation methods, tracking all material consumption and distributing costs automatically without workarounds.</p>\n            </div>\n          </details>\n          <details style="border: 1px solid #e5e7eb; border-radius: 8px; overflow: hidden;">\n            <summary style="font-family: \'Noto Sans\', sans-serif; font-size: 17px; font-weight: 600; color: #000864; padding: 16px 20px; cursor: pointer; list-style: none; display: flex; justify-content: space-between; align-items: center; background: white; transition: background 0.2s ease;">Which industries need co-product costing?<span style="font-size: 20px; color: #0369a1; transition: transform 0.2s ease; flex-shrink: 0; margin-left: 12px;">+</span></summary>\n            <div style="padding: 0 20px 16px 20px; background: white;">\n              <p style="font-family: \'Noto Sans\', sans-serif; font-size: 15px; line-height: 1.7; color: #333; margin: 0;">Co-product costing is essential for any industry where a single production process naturally yields multiple outputs. Key industries include plastics injection molding (multi-cavity molds producing different parts plus recyclable runners), food and beverage processing (primary products alongside commercially valuable by-products like cooking oils or animal feed), chemical manufacturing (reactions that inherently produce multiple compounds and recoverable solvents), and metal fabrication (stamping and die-casting operations producing finished components alongside scrap metal with resale value).</p>\n            </div>\n          </details>\n        </div>\n      </div>\n    </section>\n\n    <!-- Related Articles --><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- wp:divi/section {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Related"}}},"decoration":{"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px","syncVertical":"off","syncHorizontal":"off"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{background:transparent !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/row {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Related: Row"}}},"decoration":{"layout":{"desktop":{"value":{"flexWrap":"nowrap","display":"flex","flexDirection":"row","rowGap":"0px","columnGap":"0px"}}},"sizing":{"desktop":{"value":{"width":"100%","maxWidth":"none"}}},"spacing":{"desktop":{"value":{"padding":{"top":"0px","bottom":"0px","left":"0px","right":"0px"}}}}}},"builderVersion":"5.0.0-public-beta.8","css":{"desktop":{"value":{"freeForm":"selector{max-width:100% !important;margin:0 !important;padding:0 !important;}"}}}} -->\n<!-- wp:divi/column {"module":{"meta":{"adminLabel":{"desktop":{"value":"Co-Product Cost Accounting: The Problem Most ERPs Cannot Solve: Related: Column"}}},"decoration":{}},"css":{"desktop":{"value":{"freeForm":"selector{width:100% !important;padding:0 !important;}"}}}} -->\n<!-- wp:html --><section class="related-section" style="position: relative; overflow: hidden;">\n        <div class="dw-wave-circles" style="opacity: 0.04;"></div>\n        <div class="related-inner" style="position: relative; z-index: 2;">\n            <span class="related-label">Related Insights</span>\n            <h2 class="related-header fade-in-section">Continue Reading</h2>\n            <div class="related-grid">\n                <!-- Card 1: BOI Compliance -->\n                <a href="/blog/boi-compliance-jin-hai/" class="related-card fade-in-section">\n                    <div class="related-card-border blue"></div>\n                    <div class="related-card-body">\n                        <span class="related-card-badge compliance">BOI &amp; Compliance</span>\n                        <h3>BOI Compliance: How One Factory Eliminated 10M THB in Supplementary Taxes</h3>\n                        <p>Production-order-level reconciliation that satisfies BOI auditors and eliminates tax exposure.</p>\n                        <span class="related-card-link">Read Article <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>\n                    </div>\n                </a>\n                <!-- Card 2: LRP vs MRP -->\n                <a href="/blog/lrp-vs-mrp/" class="related-card fade-in-section">\n                    <div class="related-card-border orange"></div>\n                    <div class="related-card-body">\n                        <span class="related-card-badge production">Production Planning</span>\n                        <h3>LRP vs MRP: Why Most Thai Factories Are Planning Production Wrong</h3>\n                        <p>The difference between rough-cut capacity planning and material requirements planning -- and why you need both.</p>\n                        <span class="related-card-link">Read Article <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>\n                    </div>\n                </a>\n                <!-- Card 3: Dual Units -->\n                <a href="/blog/dual-units/" class="related-card fade-in-section">\n                    <div class="related-card-border green"></div>\n                    <div class="related-card-body">\n                        <span class="related-card-badge cost">Cost Management</span>\n                        <h3>Dual Units of Measure: Tracking What You Buy vs. What You Use</h3>\n                        <p>Purchase in kilograms, consume in meters. How dual-unit tracking prevents material variance from destroying your margins.</p>\n                        <span class="related-card-link">Read Article <svg aria-hidden="true" width="14" height="14" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2.5"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg></span>\n                    </div>\n                </a>\n            </div>\n        </div>\n    </section>\n\n    <!-- CTA Section -->\n    <section class="article-cta">\n        <div class="article-cta-inner fade-in-section">\n            <h2>Need Accurate Co-Product Costing?</h2>\n            <p>Our team can show you how DigiWin handles multi-output production -- from plastics injection to food processing to chemical manufacturing.</p>\n            <a href="/demo/" class="article-cta-btn">\n                Let\'s Talk\n                <svg aria-hidden="true" viewBox="0 0 24 24" fill="none" stroke="currentColor" stroke-width="2"><line x1="5" y1="12" x2="19" y2="12"/><polyline points="12 5 19 12 12 19"/></svg>\n            </a>\n        </div>\n    </section><!-- /wp:html -->\n<!-- /wp:divi/column -->\n<!-- /wp:divi/row -->\n<!-- /wp:divi/section -->\n<!-- /wp:divi/placeholder -->',
