INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100765, '_et_pb_custom_css', '/* === GLOBAL DIVI THEME RESET === */\n.et_pb_section,.et_pb_row,.et_pb_column,.et_pb_code,.et_pb_code_inner{font-family:\'Noto Sans\',sans-serif !important;font-weight:400 !important;font-size:16px !important;color:#333 !important}\n.et_pb_section h1,.et_pb_section h2,.et_pb_section h3,.et_pb_section h4,.et_pb_section h5,.et_pb_section h6{padding-bottom:0 !important}\n.et_pb_section:not([class*=\'tb_body\']){overflow:hidden !important;margin:0 !important}\n.et_pb_row:not([class*=\'tb_body\']){max-width:100% !important;width:100% !important;padding:0 !important;margin-top:0 !important;margin-bottom:0 !important;gap:0 !important}\n.et_pb_column:not([class*=\'tb_body\']){padding:0 !important;margin:0 !important;gap:0 !important}\n.et_pb_section .et_pb_row .et_pb_column .et_pb_text.et_pb_module{margin:0 !important;padding:0 !important}\n.section-title{line-height:1.6;-webkit-font-smoothing:auto}\n.section-subtitle{margin-left:auto;margin-right:auto;line-height:1.6}\n/* fade-in / scroll-fade-in: always visible (no JS scroll observer in Divi) */\n.fade-in,.scroll-fade-in{opacity:1 !important;transform:none !important}\n/* === DIVI MOBILE ROW PADDING OVERRIDE === */\n/* Divi injects: @media(max-width:640px){.et_pb_section .et_pb_row{padding:0 24px !important}}\n   Specificity 0,2,0. We use .et_pb_row.et_pb_row (0,2,0 doubled = 0,2,0 still, but\n   .et_pb_section prefix pushes us to 0,3,0) to beat it. */\n@media(max-width:640px){\n  .et_pb_section .et_pb_row.et_pb_row{padding:0 !important}\n}\n/* === MOBILE TOUCH TARGET RESET (WCAG 2.5.8 — 44px minimum) === */\n@media(max-width:768px){\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]),\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]),\n  select,textarea{min-height:44px}\n  a:not(.dw-logo):not(.dw-nav-link):not([class*="btn"]):not([class*="cta"]):not([class*="Cta"]){display:inline-flex;align-items:center}\n  input:not([type="hidden"]):not([type="checkbox"]):not([type="radio"]){min-height:44px}\n}\n\n@keyframes fadeIn{from{opacity:0}to{opacity:1}}\n@keyframes slide-up{from{opacity:0;transform:translateY(30px)}to{opacity:1;transform:translateY(0)}}\n@keyframes grain{0%,100%{transform:translate(0,0)}10%{transform:translate(-2%,-2%)}20%{transform:translate(2%,2%)}30%{transform:translate(-1%,1%)}40%{transform:translate(1%,-1%)}50%{transform:translate(-2%,2%)}60%{transform:translate(2%,-2%)}70%{transform:translate(-1%,-1%)}80%{transform:translate(1%,1%)}90%{transform:translate(-2%,2%)}}\n@keyframes dw-wave-drift{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n@keyframes dw-scroll{0%{transform:translateX(0)}100%{transform:translateX(-50%)}}\n/* === BLOG POST: CO-PRODUCT COST ACCOUNTING: THE PROBLEM MOST ERPS CANNOT SOLVE === */\n/* Divi section-level overrides — reset padding/margin/width on all sections */\n.et_pb_section { padding: 0 !important; min-height: auto !important; margin: 0 !important; text-align: start !important; }\n.et_pb_section .et_pb_row { max-width: 100% !important; width: 100% !important; padding: 0 !important; margin: 0 auto !important; }\n.et_pb_section .et_pb_column { padding: 0 !important; }\n/* Font smoothing reset */\n.et_pb_section, .et_pb_section * { -webkit-font-smoothing: auto !important; -moz-osx-font-smoothing: auto !important; }\n/* Divi p padding reset */\n.et_pb_section p { padding-bottom: 0 !important; }\n/* Override blog-body h2/h3 line-height from Divi defaults */\n.et_pb_section .blog-body h2, .et_pb_section .article-body h2 { line-height: 1.3 !important; }\n.et_pb_section .blog-body h3, .et_pb_section .article-body h3 { line-height: 1.35 !important; }\n/* Ensure fade-in elements are visible (no JS scroll observer in Divi) */\n.fade-in { opacity: 1 !important; transform: none !important; }\n/* Resolve CSS vars used in styles.css */\n:root { --dw-blue-text: #0369a1; --dw-gray-light: #F5F7FA; --dw-navy: #000864; }\n\n\n\n/* ===== Article Hero ===== */\n        .article-hero {\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            padding: 140px 24px 80px;\n            position: relative;\n            overflow: hidden;\n        }\n        .article-hero::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n        .article-hero-inner {\n            max-width: 800px;\n            margin: 0 auto;\n            position: relative;\n            z-index: 1;\n        }\n        .article-back-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 6px;\n            color: rgba(255,255,255,0.75);\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            text-decoration: none;\n            margin-bottom: 28px;\n            transition: all 0.3s ease;\n        }\n        .article-back-link:hover {\n            color: #0369a1;\n            gap: 10px;\n        }\n        .article-back-link svg {\n            width: 16px;\n            height: 16px;\n        }\n        .article-category-badge {\n            display: inline-block;\n            padding: 6px 16px;\n            border-radius: 50px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 11px;\n            font-weight: 500;\n            letter-spacing: 1.5px;\n            text-transform: uppercase;\n            margin-bottom: 20px;\n            background: rgba(5, 150, 105, 0.2);\n            color: #34d399;\n            border: 1px solid rgba(5, 150, 105, 0.3);\n        }\n        .article-hero h1 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(28px, 4.5vw, 44px);\n            font-weight: 700;\n            color: #fff;\n            line-height: 1.2;\n            margin-bottom: 20px;\n        }\n        .article-meta {\n            display: flex;\n            align-items: center;\n            gap: 16px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: rgba(255,255,255,0.75);\n        }\n        .article-meta-divider {\n            width: 4px;\n            height: 4px;\n            border-radius: 50%;\n            background: rgba(255,255,255,0.3);\n        }\n\n        /* ===== Article Body ===== */\n        .article-body {\n            padding: 72px 24px 100px;\n            background: #fff;\n        }\n        .article-body-inner {\n            max-width: 800px;\n            margin: 0 auto;\n        }\n        .article-body h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 28px;\n            font-weight: 700;\n            color: #000864;\n            line-height: 1.3;\n            margin-top: 48px;\n            margin-bottom: 20px;\n        }\n        .article-body h2:first-child {\n            margin-top: 0;\n        }\n        .article-body p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px;\n            color: #444;\n            line-height: 1.8;\n            margin-bottom: 20px;\n        }\n        .article-body ul {\n            margin: 0 0 24px 0;\n            padding: 0 0 0 24px;\n        }\n        .article-body ul li {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px;\n            color: #444;\n            line-height: 1.8;\n            margin-bottom: 10px;\n        }\n        .article-body ul li strong {\n            color: #000864;\n        }\n        .article-body strong {\n            color: #000864;\n            font-weight: 600;\n        }\n\n        /* Pull Quote */\n        .article-pull-quote {\n            border-left: 4px solid #00AFF0;\n            padding: 24px 32px;\n            margin: 36px 0;\n            background: transparent;\n        }\n        .article-pull-quote p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 20px;\n            font-style: italic;\n            color: #000864;\n            line-height: 1.7;\n            margin-bottom: 0;\n        }\n\n        /* Data Callout */\n        .article-data-callout {\n            background: linear-gradient(135deg, #000432 0%, #000864 100%);\n            border-radius: 16px;\n            padding: 40px;\n            margin: 40px 0;\n            text-align: center;\n            position: relative;\n            overflow: hidden;\n        }\n        .article-data-callout::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'40\' height=\'40\' viewBox=\'0 0 40 40\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'20\' cy=\'20\' r=\'1\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n        .article-data-callout-content {\n            position: relative;\n            z-index: 1;\n        }\n        .article-data-callout .callout-flow {\n            display: flex;\n            align-items: center;\n            justify-content: center;\n            gap: 12px;\n            flex-wrap: wrap;\n            margin-bottom: 20px;\n        }\n        .article-data-callout .callout-flow-item {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: clamp(18px, 3vw, 28px);\n            font-weight: 500;\n            color: #fff;\n            white-space: nowrap;\n        }\n        .article-data-callout .callout-flow-arrow {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 20px;\n            color: #00AFF0;\n        }\n        .article-data-callout .callout-result {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: clamp(32px, 5vw, 48px);\n            font-weight: 500;\n            color: #00AFF0;\n            margin-bottom: 8px;\n            line-height: 1.2;\n        }\n        .article-data-callout .callout-label {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 15px;\n            color: rgba(255,255,255,0.75);\n        }\n\n        /* Highlight Box */\n        .article-highlight-box {\n            background: #EBF5FF;\n            border-left: 4px solid #00AFF0;\n            border-radius: 0 12px 12px 0;\n            padding: 24px 28px;\n            margin: 36px 0;\n        }\n        .article-highlight-box p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 16px;\n            color: #000864;\n            line-height: 1.7;\n            margin-bottom: 0;\n        }\n\n        /* ===== Related Articles ===== */\n        .related-section {\n            padding: 80px 24px;\n            background: #F5F7FA;\n        }\n        .related-inner {\n            max-width: 1000px;\n            margin: 0 auto;\n        }\n        .related-label {\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 12px;\n            font-weight: 500;\n            color: #0369a1;\n            letter-spacing: 2px;\n            text-transform: uppercase;\n            margin-bottom: 24px;\n            display: block;\n            text-align: center;\n        }\n        .related-header {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 32px;\n            font-weight: 700;\n            color: #000864;\n            text-align: center;\n            margin-bottom: 48px;\n        }\n        .related-grid {\n            display: grid;\n            grid-template-columns: repeat(3, 1fr);\n            gap: 24px;\n        }\n        .related-card {\n            background: #fff;\n            border: 1px solid #e2e8f0;\n            border-radius: 16px;\n            overflow: hidden;\n            transition: all 0.3s ease;\n            text-decoration: none;\n            display: block;\n        }\n        .related-card:hover {\n            border-color: #00AFF0;\n            box-shadow: 0 12px 40px rgba(0, 175, 240, 0.12);\n            transform: translateY(-4px);\n        }\n        .related-card-border {\n            height: 4px;\n        }\n        .related-card-border.blue { background: #00AFF0; }\n        .related-card-border.orange { background: #F59E0B; }\n        .related-card-border.green { background: #02D28C; }\n        .related-card-body {\n            padding: 28px;\n        }\n        .related-card-badge {\n            display: inline-block;\n            padding: 4px 12px;\n            border-radius: 50px;\n            font-family: \'JetBrains Mono\', monospace;\n            font-size: 10px;\n            font-weight: 500;\n            letter-spacing: 1px;\n            text-transform: uppercase;\n            margin-bottom: 12px;\n        }\n        .related-card-badge.compliance {\n            background: rgba(0, 175, 240, 0.12);\n            color: #0369a1;\n        }\n        .related-card-badge.production {\n            background: rgba(245, 158, 11, 0.12);\n            color: #b45309;\n        }\n        .related-card-badge.cost {\n            background: rgba(5, 150, 105, 0.12);\n            color: #047857;\n        }\n        .related-card-body h3 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            font-weight: 600;\n            color: #000864;\n            line-height: 1.4;\n            margin-bottom: 12px;\n        }\n        .related-card-body p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 14px;\n            color: #5b6b80;\n            line-height: 1.6;\n            margin-bottom: 16px;\n        }\n        .related-card-link {\n            display: inline-flex;\n            align-items: center;\n            gap: 6px;\n            color: #0369a1;\n            font-family: \'Noto Sans\', sans-serif;\n            font-weight: 600;\n            font-size: 14px;\n            text-decoration: none;\n            transition: all 0.3s ease;\n        }\n        .related-card:hover .related-card-link {\n            gap: 10px;\n        }\n\n        /* ===== CTA Section ===== */\n        .article-cta {\n            padding: 100px 24px;\n            background: linear-gradient(135deg, #000432 0%, #000864 50%, #001080 100%);\n            position: relative;\n            overflow: hidden;\n        }\n        .article-cta::before {\n            content: \'\';\n            position: absolute;\n            inset: 0;\n            background-image: url("data:image/svg+xml,%3Csvg width=\'60\' height=\'60\' viewBox=\'0 0 60 60\' xmlns=\'http://www.w3.org/2000/svg\'%3E%3Cg fill=\'none\' fill-rule=\'evenodd\'%3E%3Cg fill=\'%23ffffff\' fill-opacity=\'0.03\'%3E%3Ccircle cx=\'30\' cy=\'30\' r=\'1.5\'/%3E%3C/g%3E%3C/g%3E%3C/svg%3E");\n            pointer-events: none;\n        }\n        .article-cta-inner {\n            max-width: 700px;\n            margin: 0 auto;\n            text-align: center;\n            position: relative;\n            z-index: 1;\n        }\n        .article-cta h2 {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: clamp(28px, 4vw, 40px);\n            font-weight: 700;\n            color: #fff;\n            margin-bottom: 16px;\n        }\n        .article-cta p {\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 18px;\n            color: rgba(255,255,255,0.85);\n            margin-bottom: 40px;\n            line-height: 1.7;\n        }\n        .article-cta-btn {\n            display: inline-flex;\n            align-items: center;\n            gap: 10px;\n            padding: 18px 40px;\n            background: linear-gradient(135deg, #00AFF0, #003CC8);\n            color: #fff;\n            text-decoration: none;\n            border-radius: 14px;\n            font-family: \'Noto Sans\', sans-serif;\n            font-size: 17px;\n            font-weight: 600;\n            transition: all 0.3s ease;\n        }\n        .article-cta-btn:hover {\n            transform: translateY(-3px);\n            box-shadow: 0 12px 32px rgba(0, 175, 240, 0.35);\n        }\n        .article-cta-btn svg {\n            width: 18px;\n            height: 18px;\n            transition: transform 0.3s ease;\n        }\n        .article-cta-btn:hover svg {\n            transform: translateX(3px);\n        }\n\n        /* ===== Animations ===== */\n        .fade-in-section {\n            opacity: 0;\n            transform: translateY(30px);\n            transition: opacity 0.4s ease, transform 0.4s ease;\n        }\n        .fade-in-section.is-visible {\n            opacity: 1;\n            transform: translateY(0);\n        }\n\n        /* ===== Responsive ===== */\n        @media (max-width: 768px) {\n            .article-hero {\n                padding: 120px 20px 60px;\n            }\n            .article-hero h1 {\n                font-size: 26px;\n            }\n            .article-meta {\n                flex-wrap: wrap;\n                gap: 8px;\n            }\n            .article-body {\n                padding: 48px 20px 80px;\n            }\n            .article-body h2 {\n                font-size: 22px;\n            }\n            .article-pull-quote {\n                padding: 20px 24px;\n                margin: 28px 0;\n            }\n            .article-pull-quote p {\n                font-size: 18px;\n            }\n            .article-data-callout {\n                padding: 28px 20px;\n            }\n            .article-data-callout .callout-flow {\n                flex-direction: column;\n                gap: 6px;\n            }\n            .article-data-callout .callout-flow-arrow {\n                transform: rotate(90deg);\n            }\n            .related-grid {\n                grid-template-columns: 1fr;\n                gap: 16px;\n            }\n            .related-header {\n                font-size: 26px;\n            }\n            .article-cta {\n                padding: 80px 20px;\n            }\n            .article-cta h2 {\n                font-size: 26px;\n            }\n        }\n        /* ===== Reduced Motion ===== */\n        @media (prefers-reduced-motion: reduce) {\n            .fade-in-section {\n                opacity: 1;\n                transform: none;\n                transition: none;\n            }\n            .article-back-link,\n            .related-card,\n            .related-card-link,\n            .article-cta-btn,\n            .article-cta-btn svg {\n                transition: none;\n            }\n            .related-card:hover,\n            .article-cta-btn:hover {\n                transform: none;\n            }\n            .article-cta-btn:hover svg {\n                transform: none;\n            }\n            .dw-d-bg,\n            .dw-wave-circles,\n            .dw-wave-fade {\n                animation: none;\n            }\n        }\n\n/* === TB BODY WRAPPER RESET (must be last — beats :has() rules and Divi mobile padding) === */\n/* .et-l--body doesn\'t exist on all WP/Divi versions — use [class*="tb_body"] directly */\n.et_pb_section[class*="tb_body"].et_section_regular{background:transparent !important;background-image:none !important;padding:0 !important;margin:0 !important}\n.et_pb_row[class*="tb_body"].et_pb_row{max-width:100% !important;width:100% !important;padding:0 !important;margin:0 !important}\n.et_pb_column[class*="tb_body"]{padding:0 !important;margin:0 !important}\n@media(max-width:640px){\n  .et_pb_section .et_pb_row[class*="tb_body"].et_pb_row{padding:0 !important}\n}');

-- Step 3: Ensure Divi 5 builder flags
DELETE FROM wp_postmeta WHERE post_id = 100765 AND meta_key = '_et_pb_use_builder';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100765, '_et_pb_use_builder', 'on');
DELETE FROM wp_postmeta WHERE post_id = 100765 AND meta_key = '_et_pb_use_divi_5';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100765, '_et_pb_use_divi_5', 'on');
DELETE FROM wp_postmeta WHERE post_id = 100765 AND meta_key = '_et_pb_page_layout';
INSERT INTO wp_postmeta (post_id, meta_key, meta_value) VALUES (100765, '_et_pb_page_layout', 'et_full_width_page');

-- Step 4: Flush Divi cache
DELETE FROM wp_postmeta WHERE post_id = 100765 AND meta_key LIKE '_divi_dynamic_assets%';
DELETE FROM wp_postmeta WHERE post_id = 100765 AND meta_key LIKE '_divi_%canvas%';
